const feed = $('Read Feeds').item.json;
const xmlString = $input.first().json.data || 
                  $input.first().json.body || 
                  String($input.first().json);

const getText = (xml, tag) => {
  const re = new RegExp(
    `<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>` +
    `|<${tag}[^>]*>([^<]*)<\\/${tag}>`, 'i'
  );
  const m = xml.match(re);
  return m ? (m[1] || m[2] || '').trim() : '';
};

const getAttr = (xml, tag, attr) => {
  const re = new RegExp(`<${tag}[^>\\n]*\\s${attr}=['"](.*?)['"]`, 'i');
  const m = xml.match(re);
  return m ? m[1] : '';
};

const episodes = [];
const itemRe = /<item>([\s\S]*?)<\/item>/g;
let match;

while ((match = itemRe.exec(xmlString)) !== null) {
  const item = match[1];
  const audioUrl = getAttr(item, 'enclosure', 'url');
  if (!audioUrl) continue;

  // Try itunes:episode first
  let epNum = parseInt(getText(item, 'itunes:episode')) || 0;

  // If no itunes:episode tag, extract from title (e.g., "32 - AI PM: No-code Tools")
  if (epNum === 0) {
    const title = getText(item, 'title');
    const titleMatch = title.match(/^(\d+)\s*[-–—]/);
    if (titleMatch) {
      epNum = parseInt(titleMatch[1]);
    }
  }

  episodes.push({
    // Unique tracking ID
    episode_id: `${feed.feed_id}_${epNum}`,

    // Feed metadata (from Sheets)
    feed_id: feed.feed_id,
    feed_name: feed.feed_name,
    collection_name: feed.collection_name,
    language: feed.language,

    // Episode metadata (from RSS)
    episode_number: epNum,
    title: getText(item, 'title'),
    description: getText(item, 'description'),
    pub_date: getText(item, 'pubDate').substring(0, 16),
    duration: getText(item, 'itunes:duration'),
    audio_url: audioUrl
  });
}

episodes.sort((a, b) => a.episode_number - b.episode_number);
return episodes.map(ep => ({ json: ep }));

const runpod  = $input.item.json;
const episode = $('Loop Over Items').item.json;

return {
  ...episode,
  job_id:     runpod.id,
  job_status: runpod.status || 'IN_QUEUE'
};

const poll = $input.item.json;
const episode = $('Loop Over Items').item.json;  

let transcript = '';

if (poll.status === 'COMPLETED' && poll.output?.[0]?.result?.[0]) {
  // Segments are inside result[0]
  const segments = poll.output[0].result[0];

  let lines = [];
  let currentSpeaker = null;
  let currentText = '';

  for (const segment of segments) {
    const speaker = segment.speakers?.[0] ?? 'SPEAKER_?';
    const text = (segment.text ?? '').trim();

    if (!text) continue;

    if (speaker !== currentSpeaker) {
      if (currentText) {
        lines.push(`**${currentSpeaker}:** ${currentText.trim()}`);
      }
      currentSpeaker = speaker;
      currentText = text;
    } else {
      currentText += ' ' + text;
    }
  }

  // Don't forget the last speaker's text
  if (currentText) {
    lines.push(`**${currentSpeaker}:** ${currentText.trim()}`);
  }

  transcript = lines.join('\n\n');
}

return {
  ...episode,
  job_id: poll.id || episode.job_id,
  job_status: poll.status,
  transcript: transcript
};

// Get all episodes from RSS (via Parse Episodes)
const episodes = $('Parse Episodes').all().map(i => i.json);

// Get existing rows from sheet (may be empty on first run)
let existingRows = [];
try {
  existingRows = $('Read Episodes Sheet').all().map(i => i.json);
} catch (e) {
  // Sheet is empty, that's fine
  existingRows = [];
}

// Build lookup map by episode_id
const existing = {};
for (const row of existingRows) {
  if (row.episode_id) {
    existing[row.episode_id] = row;
  }
}

const TWO_HOURS_MS = 2 * 60 * 60 * 1000;
const now = new Date();

const toProcess = [];
const toUpdate = [];
const toInsert = [];

for (const ep of episodes) {
  const row = existing[ep.episode_id];

  if (!row) {
    // ═══ NEW EPISODE ═══
    // Not in sheet yet - add it and queue for processing
    toInsert.push({
      episode_id: ep.episode_id,
      feed_id: ep.feed_id,
      episode_number: ep.episode_number,
      title: ep.title,
      pub_date: ep.pub_date,
      duration: ep.duration,
      audio_url: ep.audio_url,
      status: 'new',
      retry_count: 0,
      runpod_job_id: '',
      gdrive_file_id: '',
      transcript_chars: '',
      openbrain_doc_id: '',
      started_at: '',
      completed_at: '',
      error_message: '',
      last_updated: now.toISOString()
    });
    toProcess.push({ ...ep, retry_count: 0 });
    continue;
  }

  // Episode exists in sheet - check status
  const status = row.status;
  const retryCount = parseInt(row.retry_count) || 0;
  const startedAt = row.started_at ? new Date(row.started_at) : null;

  if (status === 'completed' || status === 'skipped') {
    // ═══ ALREADY DONE ═══
    continue;
  }

  if (status === 'processing') {
    // ═══ CHECK IF STUCK ═══
    if (startedAt && (now - startedAt) > TWO_HOURS_MS) {
      // Stuck for over 2 hours
      if (retryCount >= 3) {
        // Max retries exceeded - mark as permanently failed
        toUpdate.push({
          episode_id: ep.episode_id,
          status: 'failed',
          error_message: 'Max retries exceeded (stuck in processing)',
          last_updated: now.toISOString()
        });
      } else {
        // Reset to new and retry
        toUpdate.push({
          episode_id: ep.episode_id,
          status: 'new',
          retry_count: retryCount + 1,
          started_at: '',
          last_updated: now.toISOString()
        });
        toProcess.push({ ...ep, retry_count: retryCount + 1 });
      }
    }
    // If within 2 hours, skip (still processing normally)
    continue;
  }

  if (status === 'failed') {
    // ═══ RETRY FAILED ═══
    if (retryCount < 3) {
      toUpdate.push({
        episode_id: ep.episode_id,
        status: 'new',
        retry_count: retryCount + 1,
        error_message: '',
        last_updated: now.toISOString()
      });
      toProcess.push({ ...ep, retry_count: retryCount + 1 });
    }
    // If retryCount >= 3, permanently failed - skip
    continue;
  }

  if (status === 'new') {
    // ═══ RESUME INTERRUPTED ═══
    toProcess.push({ ...ep, retry_count: retryCount });
    continue;
  }
}

// Return summary for debugging + the three arrays
return [{
  json: {
    summary: {
      total_in_rss: episodes.length,
      total_in_sheet: existingRows.length,
      to_insert: toInsert.length,
      to_update: toUpdate.length,
      to_process: toProcess.length
    },
    toInsert,
    toUpdate,
    toProcess
  }
}];

const data = $('Check Status & Filter').first().json;

// If nothing to insert, return empty (but don't block flow)
if (!data.toInsert || data.toInsert.length === 0) {
  return [];
}

// Return each row as a separate item for Google Sheets
return data.toInsert.map(row => ({ json: row }));

const data = $('Check Status & Filter').first().json;

if (!data.toUpdate || data.toUpdate.length === 0) {
  return [];
}

return data.toUpdate.map(row => ({ json: row }));

const data = $('Check Status & Filter').first().json;

if (!data.toProcess || data.toProcess.length === 0) {
  return [];
}

return data.toProcess.map(row => ({ json: row }));

const claudeResp = $input.item.json;
const episode = $('Prepare for Claude').item.json;  // Get episode data from before Claude API call

let summaryHtml = claudeResp.content?.[0]?.text || '<p>שגיאה ביצירת הסיכום</p>';

// Remove markdown code block wrappers if Claude added them
summaryHtml = summaryHtml
  .replace(/^```html\s*/i, '')
  .replace(/^```\s*/gm, '')
  .replace(/```\s*$/g, '')
  .trim();

// Build the full email
const fullHtml = `
<div dir="ltr" style="font-family: -apple-system, Arial, sans-serif; padding: 24px; background: #ffffff;">
  <div style="background: linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%); padding: 28px; border-radius: 16px; margin-bottom: 28px;">
