  </div>
  <p style="color: #9ca3af; font-size: 14px; margin-top: 32px; text-align: center; border-top: 1px solid #e5e7eb; padding-top: 16px;">
    🤖 נוצר אוטומטית
  </p>
</div>
`;

return {
  ...episode,
  summary: summaryHtml,
  summary_html: fullHtml
};

const data = $input.first().json;  // Changed .item to .first() (runOnceForAllItems mode)

// Escape the transcript for safe JSON embedding
const safeTranscript = (data.transcript || '')
  .substring(0, 100000)
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

const safeDescription = (data.description || '')
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

const safeTitle = (data.title || '')
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"');

return {
  ...data,
  safe_transcript: safeTranscript,
  safe_description: safeDescription,
