const data = $input.first().json;  // Changed .item to .first()
const transcript = data.transcript || '';

// Extract first ~2000 chars to identify speakers from intro
const introSection = transcript.substring(0, 2000);

// Escape for safe JSON embedding
const safeIntro = introSection
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

// Find all unique speaker labels
const speakerLabels = [...new Set(transcript.match(/SPEAKER_\d+/g) || [])];

