const claudeResp = $input.first().json;
const episode = $('Identify Speakers').first().json;  // KEEP .first() - this has the transcript!

// Parse Claude's speaker mapping
let speakerMap = {};
try {
  const responseText = claudeResp.content?.[0]?.text || '{}';
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    speakerMap = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  speakerMap = {
    "SPEAKER_00": "דובר 1",
    "SPEAKER_01": "דובר 2"
  };
}

// Replace speaker labels in transcript
let transcript = episode.transcript || '';

for (const [label, name] of Object.entries(speakerMap)) {
  const regex = new RegExp(`\\*\\*${label}:\\*\\*`, 'g');
  transcript = transcript.replace(regex, `**${name}:**`);
}

return {
  ...episode,
  transcript: transcript,
  speaker_map: speakerMap
};

// Get data from Extract Summary (direct input)
const data = $input.item.json;

// Format title for searchability
const pubDate = data.pub_date ? data.pub_date.split(',')[0].trim() : '';
const title = `${data.feed_name} | פרק ${data.episode_number} | ${pubDate} | ${data.title}`;

// Get speaker names for metadata
const speakerNames = data.speaker_map ? Object.values(data.speaker_map).join(', ') : '';

// Escape content for JSON
const safeContent = (data.transcript || '')
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t');

const safeTitle = title
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"');

return {
  collection: 'Podcasts',
  title: safeTitle,
  content: safeContent,
  source_url: data.audio_url,
  author: speakerNames || data.feed_name,

  episode_id: data.episode_id,
  transcript_length: (data.transcript || '').length,
  episode_number: data.episode_number,
  summary: data.summary
};

const episode = $('Loop Over Items').item.json;  // Keep .item but mode must be runOnceForEachItem

const currentRetry = parseInt(episode.retry_count) || 0;
const newRetryCount = currentRetry + 1;

return {
  episode_id: episode.episode_id,
  retry_count: newRetryCount,
  should_give_up: newRetryCount >= 3,
  status: newRetryCount >= 3 ? 'failed' : 'failed',
  error_message: newRetryCount >= 3 
    ? 'Max retries exceeded (3 attempts)' 
    : 'RunPod transcription failed - will retry'
};

// Get input from Prepare for Open Brain
const input = $('Prepare for Open Brain').item.json;  // Changed .first() to .item

// Hardcoded Podcasts collection ID (from your Supabase)
const PODCASTS_COLLECTION_ID = 'YOUR_PODCASTS_COLLECTION_ID';

return {
  ...input,
  collection_id: PODCASTS_COLLECTION_ID,
  collection_name: 'Podcasts'
};

const prepData = $('Prepare Document Data').item.json;  // Changed .first() to .item
const checkResult = $input.item.json;  // Changed .first() to .item

// Handle array response from Supabase
let existingDocs = Array.isArray(checkResult) ? checkResult : [];

const existingDoc = existingDocs.length > 0 && existingDocs[0].id ? existingDocs[0] : null;

return {
  ...prepData,
  existing_doc_id: existingDoc ? existingDoc.id : null,
  needs_delete: !!existingDoc
};

const input = $input.first().json;  // Now comes from Merge Doc Response

// document_id is already in input from Merge Doc Response
const docId = input.document_id;

if (!docId) {
  throw new Error('Failed to get document ID: ' + JSON.stringify(input));
}

const collectionId = input.collection_id;
const content = input.content || '';

// Chunk function - paragraph aware
function chunkText(text, maxSize = 800, overlap = 100) {
  const chunks = [];
  const paragraphs = text.split(/\n\n+/);
  let currentChunk = '';

  for (const para of paragraphs) {
    const trimmedPara = para.trim();
    if (!trimmedPara) continue;

    if (currentChunk.length + trimmedPara.length + 2 <= maxSize) {
      currentChunk += (currentChunk ? '\n\n' : '') + trimmedPara;
    } else {
      if (currentChunk) {
        chunks.push(currentChunk);
        // Keep overlap
        const words = currentChunk.split(' ');
        const overlapWords = words.slice(-Math.ceil(overlap / 5));
        currentChunk = overlapWords.join(' ') + '\n\n' + trimmedPara;
      } else {
        // Paragraph too long, split by sentences
        const sentences = trimmedPara.match(/[^.!?]+[.!?]+/g) || [trimmedPara];
        for (const sent of sentences) {
          if (currentChunk.length + sent.length <= maxSize) {
            currentChunk += sent;
          } else {
            if (currentChunk) chunks.push(currentChunk);
            currentChunk = sent;
          }
        }
      }
    }
  }

  if (currentChunk) chunks.push(currentChunk);
  return chunks;
}

const chunks = chunkText(content, 800, 100);

// Return array of chunks
return chunks.map((chunk, index) => ({
  json: {
    document_id: docId,
    collection_id: collectionId,
    content: chunk,
    chunk_index: index,
    total_chunks: chunks.length,
    episode_id: input.episode_id,
    transcript_length: input.transcript_length
  }
}));

// Insert Document response contains all inserted fields (due to Prefer: return=representation)
const docResponse = $input.first().json;
const docArray = Array.isArray(docResponse) ? docResponse : [docResponse];
const doc = docArray[0];

// All data comes from the Supabase response
const docId = doc.id;
const collectionId = doc.collection_id;
const content = doc.content || '';
const title = doc.title || '';

// Extract episode_id from title (format: "LangTalks | פרק 13 | Tue | 13 - ...")
const episodeMatch = title.match(/פרק\s*(\d+)/);
const episodeNumber = episodeMatch ? parseInt(episodeMatch[1]) : 0;

// Construct episode_id from feed name pattern
const feedMatch = title.match(/^([^|]+)/);
const feedName = feedMatch ? feedMatch[1].trim().toLowerCase().replace(/\s+/g, '') : 'unknown';
const episodeId = `${feedName}_${episodeNumber}`;

return {
  document_id: docId,
  collection_id: collectionId,
  content: content,
  title: title,
  episode_id: episodeId,
  episode_number: episodeNumber,
  transcript_length: content.length
};

// After Open Brain ingestion, retrieve the original episode data
// which has the transcript, title, description, etc. needed for summarization

const episode = $('Loop Over Items').item.json;

// Get Open Brain metadata from the ingestion flow
const openBrainData = $input.item.json;

// Combine: episode data + any useful metadata from ingestion
return {
  // Full episode data for summarization
  ...episode,
  openbrain_completed: true,
  document_id: openBrainData.document_id,
  transcript_length: openBrainData.transcript_length
};

// Get ALL chunks from Chunk Transcript
const items = $input.all();
const chunks = items.map(item => item.json);

if (chunks.length === 0) {
  return [{ json: { success: false, error: 'No chunks to process' } }];
}

// DEBUG: Log transcript info
console.log('Episode:', chunks[0].episode_id, 
            '| Transcript length:', chunks[0].transcript_length,
            '| Chunk count:', chunks.length);

// Process in batches of 5 with delays
const BATCH_SIZE = 5;
const allChunksWithEmbeddings = [];

for (let i = 0; i < chunks.length; i += BATCH_SIZE) {
  const batch = chunks.slice(i, i + BATCH_SIZE);
  const texts = batch.map(chunk => chunk.content);

  console.log(`Batch ${Math.floor(i/BATCH_SIZE) + 1}: chunks ${i} to ${i + batch.length - 1}`);

  // Get embeddings for this batch
  const embeddingResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/embeddings',
    headers: {
      'Authorization': 'Bearer ' + $vars.OPENROUTER_API_KEY,  
      'Content-Type': 'application/json'
    },
    body: {
      model: 'openai/text-embedding-3-small',
      input: texts
    },
    json: true
  });

  const embeddings = embeddingResponse.data || [];

  // Match embeddings to chunks
  for (let j = 0; j < batch.length; j++) {
    const embeddingArray = embeddings[j]?.embedding || [];
    // Format embedding as a string for pgvector
    const embeddingString = '[' + embeddingArray.join(',') + ']';

    allChunksWithEmbeddings.push({
      document_id: batch[j].document_id,
      collection_id: batch[j].collection_id,
      content: batch[j].content,
      chunk_index: batch[j].chunk_index,
      embedding: embeddingString,
      metadata: {}
    });
  }

  // Delay between batches (except for last batch)
  if (i + BATCH_SIZE < chunks.length) {
    await new Promise(resolve => setTimeout(resolve, 300));
  }
}

// Insert all chunks to Supabase
let insertResponse;
try {
  insertResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://YOUR_PROJECT.supabase.co/rest/v1/chunks',
    headers: {
      'apikey': $vars.SUPABASE_API_KEY,
      'Authorization': 'Bearer ' + $vars.SUPABASE_API_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: allChunksWithEmbeddings,
    json: true,
    returnFullResponse: true
  });
} catch (error) {
  // Log the first chunk to debug
  console.log('First chunk being inserted:', JSON.stringify({
    document_id: allChunksWithEmbeddings[0].document_id,
    collection_id: allChunksWithEmbeddings[0].collection_id,
    content_length: allChunksWithEmbeddings[0].content?.length,
    chunk_index: allChunksWithEmbeddings[0].chunk_index,
    embedding_length: allChunksWithEmbeddings[0].embedding?.length
  }));

  // Try to get the actual Supabase error
  console.log('Error message:', error.message);
  console.log('Error response:', JSON.stringify(error.response?.data || error.cause || 'no details'));

  throw error;
}
console.log('Inserted', allChunksWithEmbeddings.length, 'chunks');

return [{
  json: {
    success: true,
    episode_id: chunks[0].episode_id,
    total_chunks: chunks.length,
    transcript_length: chunks[0].transcript_length
  }
}];
